const company = $('Einzeln verarbeiten').first().json;
const _raw = $('Daten abrufen').first().json;
const kz = _raw.kennzahlen || {};
const _debug = {
  allKeys: Object.keys(kz),
};

// ── Hilfsfunktionen ───────────────────────────────────────────────────────────
function parseNum(str) {
  if (!str) return null;
  const s = String(str).replace(/\xa0/g,'').replace(/\./g,'').replace(',','.').replace(/[^0-9.\-]/g,'');
  const n = parseFloat(s);
  return isNaN(n) ? null : n;
}
function toNums(arr) {
  return (arr || []).map(parseNum).filter(v => v !== null);
}
function latestVal(arr) {
  const n = toNums(arr);
  return n.length ? n[n.length - 1] : null;
}
function pct(nums, threshold) {
  if (!nums || !nums.length) return null;
  return Math.round(nums.filter(v => v >= threshold).length / nums.length * 100);
}
function pctBelow(nums, threshold) {
  if (!nums || !nums.length) return null;
  return Math.round(nums.filter(v => v <= threshold).length / nums.length * 100);
}
function findKey(patterns) {
  let best = null;
  let bestLen = 0;
  for (const key of Object.keys(kz)) {
    if (patterns.some(p => p.test(key))) {
      const len = (kz[key] || []).length;
      if (len > bestLen) { best = kz[key]; bestLen = len; }
    }
  }
  return best;
}

// ── Kennzahlen auslesen (exakte Key-Namen von ariva.de) ───────────────────────
const fiskalArr  = findKey([/fiskaljahr/]);
const kgvArr     = findKey([/kgv\s*\(kurs.gewinn/]);
const kbvArr     = findKey([/kbv\s*\(kurs.buchwert/]);
const ekrArr     = findKey([/eigenkapitalrendite/]);
const umsatzArr  = findKey([/umsatzrendite/]);
const divArr     = findKey([/dividendenrendite/]);
const ekqArr     = findKey([/eigenkapitalquote/]);
const verschArr  = findKey([/verschuldungsgrad/]);
const fcfArr     = findKey([/free cashflow/]);
const ocfArr     = findKey([/operativer cashflow/]);

// ── Kriterien ─────────────────────────────────────────────────────────────────
// C1: Börsenlisting > 15 Jahre
const ipoYear = fiskalArr && fiskalArr.length ? parseInt(fiskalArr[0]) : null;
const currentYear = new Date().getFullYear();
const c1 = ipoYear ? ((currentYear - ipoYear) > 15 ? 'Ja' : 'Nein') : 'unbekannt';

// C2: Positiver Cashflow (FCF bevorzugt, sonst OCF)
const fcfCurr = latestVal(fcfArr);
const ocfCurr = latestVal(ocfArr);
const cashflow = fcfCurr ?? ocfCurr;
const c2 = cashflow !== null ? (cashflow > 0 ? 'Ja' : 'Nein') : 'unbekannt';

// C3: EKQ >= 30% — % der letzten 10 Jahre
const ekqH = toNums(ekqArr).slice(-10);
const c3 = ekqH.length ? pct(ekqH, 30) + '%' : 'unbekannt';

// C4: Aktueller Verschuldungsgrad
const c4 = latestVal(verschArr) !== null ? latestVal(verschArr) + '%' : 'unbekannt';

// C5: Aktuelles KGV
const c5 = latestVal(kgvArr) !== null ? String(latestVal(kgvArr)) : 'unbekannt';

// C6: KBV >= 2 — % der letzten 10 Jahre
const kbvH = toNums(kbvArr).slice(-10);
const c6 = kbvH.length ? pctBelow(kbvH, 2) + '%' : 'unbekannt';

// C7: EKR >= 10% — % der letzten 10 Jahre
const ekrH = toNums(ekrArr).slice(-10);
const c7 = ekrH.length ? pct(ekrH, 10) + '%' : 'unbekannt';

// C8: Dividendenrendite >= 2,5% — % der letzten 10 Jahre
const divH = toNums(divArr).slice(-10);
const c8 = divH.length ? pct(divH, 2.5) + '%' : 'unbekannt';

// C9: Global tätig — aus Branche ableiten (grobe Heuristik)
const br = String(company.branche || '').toLowerCase();
const c9 = /auto|pharma|tech|chemie|energie|versicherung|bank|industrie|konsumgüter|it|software|halbleiter/.test(br) ? 'Ja' : 'unbekannt';

// C10: Umsatzrendite >= 5% — % der letzten 10 Jahre
const umsatzH = toNums(umsatzArr).slice(-10);
const c10 = umsatzH.length ? pct(umsatzH, 5) + '%' : 'unbekannt';

// C11: Aktuelle Dividendenrendite
const c11 = latestVal(divArr) !== null ? latestVal(divArr) + '%' : 'unbekannt';

// ── Ergebnis speichern ────────────────────────────────────────────────────────
const sd = $getWorkflowStaticData('global');
if (!sd.results) sd.results = [];
if (c1 !== 'Nein') sd.results.push({
  '#': company.id,
  Name: company.name,
  ISIN: company.isin,
  Branche: company.branche,
  'C1: DivRendite aktuell': c11,
  'C2: Boerse >15 Jahre': c1,
  'C3: Positiver Cashflow': c2,
  'C4: Eigenkapitalquote >=30% (letzte 10J)': c3,
  'C5: Verschuldungsgrad aktuell': c4,
  'C6: KGV aktuell': c5,
  'C7: KBV <=2 (letzte 10J)': c6,
  'C8: Eigenkapitalrendite >=10% (letzte 10J)': c7,
  'C9: DivRendite >=2,5% (letzte 10J)': c8,
  'C10: Umsatzrendite >=5% (letzte 10J)': c10,
  'C11: Global taetig': c9,
  _sortKey: latestVal(divArr) ?? -999
});

return [{ json: { name: company.name, c11 } }];

const company = $input.first().json;

const result = await new Promise((resolve, reject) => {
  const http = require('http');
  const body = JSON.stringify({ kennzahlenUrl: company.url, timeout: 40000 });
  const req = http.request({
    hostname: 'playwright',
    port: 3001,
    path: '/extract-kennzahlen',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { reject(e); } });
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

return [{ json: result }];

const sd = $getWorkflowStaticData('global');
if (!sd.results || sd.results.length === 0) return [];

const rows = [...sd.results]
  .sort((a, b) => b._sortKey - a._sortKey)
  .map(({ _sortKey, ...r }) => r);

return [{ json: { rows, filename: 'aktien-dividenden-analyse.xlsx' } }];
